const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const llmUrl = 'https://api.example.com/generate'; // Replace with actual LLM API endpoint

app.post('/generate-code', async (req, res) => {
  const { description } = req.body;

  if (!description) {
    return res.status(400).json({ error: 'Description is required' });
  }

  try {
    const response = await axios.post(llmUrl, { prompt: description });
    const generatedCode = response.data.code;

    // Execute the generated code (simplified example)
    const vm = require('vm');
    let result;
    try {
      result = vm.runInNewContext(generatedCode);
    } catch (error) {
      return res.status(500).json({ error: 'Error executing generated code', details: error.message });
    }

    res.json({ generatedCode, result });
  } catch (error) {
    res.status(500).json({ error: 'Failed to generate code', details: error.message });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});